<?php
namespace App\Http\Controllers\Dashboard;use App\Http\Controllers\Controller;use App\Services\Notifications\{FcmClient,FcmSettings};use App\Services\Security\AuditLogger;use Illuminate\Http\{RedirectResponse,Request};
class FcmSettingsController extends Controller{public function update(Request$r,FcmSettings$settings):RedirectResponse{abort_unless($r->user()->role==='super_admin',403);$settings->save($r,$r->user()->hotel);AuditLogger::record($r,'fcm_configuration_updated','settings','critical','Hotel Firebase configuration updated.',$r->user()->hotel);return back()->with('success','Firebase configuration saved.');}public function test(Request$r,FcmSettings$settings,FcmClient$client):RedirectResponse{abort_unless($r->user()->role==='super_admin',403);try{$settings->test($r->user()->hotel,$client);return back()->with('success','Firebase authentication succeeded.');}catch(\Throwable$e){return back()->withErrors(['fcm'=>$e->getMessage()]);}}}
